// Get items from Apify
const items = $input.all();
const extractedData = [];
const maxItems = 50;

// Regex patterns for phone numbers (supports multiple formats)
const phonePatterns = [
  /\+?\d{1,4}?[-.\s]?\(?\d{1,3}?\)?[-.\s]?\d{1,4}[-.\s]?\d{1,4}[-.\s]?\d{1,9}/g,
  /\b\d{10,}\b/g,
  /\(\d{3}\)\s*\d{3}[-.\s]?\d{4}/g,
  /\d{4}[-.\s]?\d{7}/g, // Pakistan format
  /03\d{9}/g // Pakistan mobile format
];

// Function to clean phone numbers
function cleanPhoneNumber(phone) {
  return phone.replace(/[^0-9+]/g, '').trim();
}

// Function to validate phone number length
function isValidPhone(phone) {
  const cleaned = cleanPhoneNumber(phone);
  return cleaned.length >= 10 && cleaned.length <= 15;
}

for (let i = 0; i < items.length && extractedData.length < maxItems; i++) {
  const item = items[i].json;

  // Combine text fields where phone numbers might appear
  const textContent = [
    item.text || '',
    item.description || '',
    item.message || '',
    item.caption || '',
    item.content || '',
    item.body || ''
  ].join(' ');

  // Extract phone numbers
  let phoneNumbers = [];
  phonePatterns.forEach(pattern => {
    const matches = textContent.match(pattern);
    if (matches) {
      phoneNumbers = phoneNumbers.concat(matches);
    }
  });

  // Clean and validate phone numbers
  phoneNumbers = phoneNumbers
    .map(phone => cleanPhoneNumber(phone))
    .filter(phone => isValidPhone(phone));

  // Remove duplicates
  phoneNumbers = [...new Set(phoneNumbers)];

  // If phone numbers found, add to results
  if (phoneNumbers.length > 0) {
    phoneNumbers.forEach(phone => {
      if (extractedData.length < maxItems) {
        extractedData.push({
          name: item.authorName || item.userName || item.author || item.user || 'Unknown',
          phoneNumber: phone,
          source: item.url || item.postUrl || 'N/A',
          date: new Date().toISOString().split('T')[0],
          timestamp: new Date().toISOString()
        });
      }
    });
  }
}

// Return extracted data
if (extractedData.length === 0) {
  return [{ json: { message: 'No phone numbers found', count: 0 } }];
}

return extractedData.map(data => ({ json: data }));

// Extract input from AI agent - handle nested query object
const inputData = $json.query || $json;

const key = inputData.key;
const value = inputData.value;
const conversationId = inputData.conversation_id || 'unknown';

// Validation
if (!key || typeof key !== 'string' || key.trim().length === 0) {
  throw new Error('❌ key is required and must be a non-empty string');
}

if (!value) {
  throw new Error('❌ value is required');
}

if (!conversationId) {
  throw new Error('❌ conversation_id is required');
}

// Sanitize key
const sanitizedKey = key.trim().substring(0, 100);

// Parse value if it's a string that looks like JSON
let parsedValue = value;
if (typeof value === 'string') {
  try {
    parsedValue = JSON.parse(value);
  } catch (e) {
    // Keep as string if not valid JSON
    parsedValue = value;
  }
}

return [{
  json: {
    key: sanitizedKey,
    value: parsedValue,
    conversationId: conversationId,
    timestamp: new Date().toISOString()
  }
}];

const saved = $input.first().json;
const original = $('Validate Input').first().json;

return [{
  json: {
    success: true,
    message: `✅ Context stored successfully\n\n🔑 Key: ${original.key}\n💾 Stored for conversation: ${original.conversationId}`,
    details: {
      key: saved.context_key,
      value: saved.context_value,
      conversationId: saved.conversation_id,
      storedAt: saved.updated_at
    }
  }
}];
